import "../pages/styles/Navbar.css";
import { useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  const role = localStorage.getItem("role");

  const logout = () => {
    localStorage.clear();
    navigate("/");
  };

  return (
    <nav className="navbar">
      <div className="logo">
        Book<span>Sphere</span>
      </div>

      <div className="nav-links">
        <a href="/">Archive</a>
        <a href="/books">The Library</a>
        <a href="/dashboard">Study Hall</a>

        {role === "Student" && <a href="/borrowed">My Books</a>}

        {!role ? (
          <button className="enter-btn" onClick={() => navigate("/auth")}>
            ENTER
          </button>
        ) : (
          <button className="enter-btn" onClick={logout}>
            LOGOUT
          </button>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
